const uint8_t CAVE_X[CAVE_COUNT]={7,21,42,4};
const uint8_t CAVE_Y[CAVE_COUNT]={13,14,14,23};
static const uint8_t SOLID_TILES[]={TILE_TREE,TILE_CACTUS,TILE_HOUSE,TILE_STONE,TILE_WATER};
void world_init(void){set_bkg_data(0,11,NULL);}
void world_draw(int16_t cx,int16_t cy){
    for(uint8_t row=0;row<SCREEN_H;row++){
        int16_t wy=cy+row; if(wy<0||wy>=WORLD_H) continue;
        for(uint8_t col=0;col<SCREEN_W;col++){
            int16_t wx=cx+col; if(wx<0||wx>=WORLD_W) continue;
            set_bkg_tiles(col,row,1,1,&WORLD_MAP[wy][wx]);
        }
    }
}
uint8_t world_get_tile(int16_t x,int16_t y){
    if(x<0||x>=WORLD_W||y<0||y>=WORLD_H) return TILE_STONE;
    return WORLD_MAP[y][x];
}
uint8_t world_is_solid(int16_t x,int16_t y){
    uint8_t t=world_get_tile(x,y);
    for(uint8_t i=0;i<5;i++) if(t==SOLID_TILES[i]) return 1;
    return 0;
}
uint8_t world_is_cave_entrance(int16_t x,int16_t y,uint8_t *cave_id){
    for(uint8_t i=0;i<CAVE_COUNT;i++)
        if(x==CAVE_X[i]&&y==CAVE_Y[i]){*cave_id=i;return 1;}
    return 0;
}
